ALGORITHM SparkRDDProcessing
INPUT: Raw data collection or file path
OUTPUT: Aggregated result

BEGIN
    // Step 1: Create SparkContext (Driver)
    sparkContext = CREATE SparkContext(clusterManager, appName)

    // Step 2: Create RDD from data (Lazy - just defines data)
    inputRDD = PARALLELIZE(data, numPartitions)
    // OR: inputRDD = TEXTFILE(path, minPartitions)

    // Step 3: Apply TRANSFORMATIONS (Lazy - builds DAG, no execution)
    filteredRDD = TRANSFORM(inputRDD, predicate)
    // Example: filter(lambda x: x > threshold)

    mappedRDD = TRANSFORM(filteredRDD, function)
    // Example: map(lambda x: (x.key, x.value))

    pairedRDD = TRANSFORM(mappedRDD, toKeyValue)
    // Example: map(lambda x: (x, 1))

    reducedRDD = TRANSFORM(pairedRDD, reduceByKey)
    // Example: reduceByKey(lambda a,b: a+b)

    // Step 4: Apply ACTION (Eager - triggers execution of entire DAG)
    result = ACTION(reducedRDD)
    // Example: collect(), count(), reduce(), take(n)

    // Step 5: Return result to driver
    RETURN result

    // FAULT TOLERANCE: If partition lost, recompute from lineage
    // Lineage: inputRDD -> filteredRDD -> mappedRDD -> reducedRDD
END
